objects.draw:
function(ctx, obj) {
  ctx.save();
  if (obj.rotationAngle) {
    ctx.translate(obj.x, obj.y);
    ctx.rotate(obj.rotationAngle);
    ctx.translate(-obj.x, -obj.y);
  }
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, Math.PI * 2);
  ctx.fillStyle = obj.fill;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w - 6, 0, Math.PI * 2);
  ctx.fillStyle = '#1e293b';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w * 0.2, 0, Math.PI * 2);
  ctx.fillStyle = '#0f172a';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w * 0.12, 0, Math.PI * 2);
  ctx.fillStyle = '#facc15';
  ctx.fill();
  ctx.beginPath();
  for (let i = 0; i < 6; i++) {
    const angle = (i * Math.PI * 2) / 6;
    const innerX = obj.x + Math.cos(angle) * (obj.w * 0.25);
    const innerY = obj.y + Math.sin(angle) * (obj.w * 0.25);
    const outerX = obj.x + Math.cos(angle) * (obj.w - 8);
    const outerY = obj.y + Math.sin(angle) * (obj.w - 8);
    ctx.moveTo(innerX, innerY);
    ctx.lineTo(outerX, outerY);
  }
  ctx.strokeStyle = '#475569';
  ctx.lineWidth = 1.5;
  ctx.stroke();
  ctx.restore();
  if (obj.leftMassObj && obj.rightMassObj) {
    ctx.save();
    ctx.beginPath();
    const leftMassTop = obj.leftMassObj.y;
    const rightMassTop = obj.rightMassObj.y;
    const leftContactX = obj.x - obj.w * 0.55;
    const leftContactY = obj.y + obj.w * 0.15;
    const rightContactX = obj.x + obj.w * 0.55;
    const rightContactY = obj.y + obj.w * 0.15;
    ctx.moveTo(obj.leftMassObj.x, leftMassTop);
    ctx.lineTo(leftContactX, leftContactY);
    ctx.moveTo(leftContactX, leftContactY);
    ctx.quadraticCurveTo(obj.x, obj.y - 5, rightContactX, rightContactY);
    ctx.moveTo(rightContactX, rightContactY);
    ctx.lineTo(obj.rightMassObj.x, rightMassTop);
    ctx.strokeStyle = obj.ropeColor;
    ctx.lineWidth = obj.ropeWidth;
    ctx.lineCap = 'round';
    ctx.stroke();
    ctx.restore();
  }
}

objects.update:
function(obj, dt) {
  if (!obj.leftMassObj || !obj.rightMassObj) return;
  const m1 = obj.leftMass;
  const m2 = obj.rightMass;
  const I = obj.momentOfInertia;
  const r = obj.w / 100;
  const g = Lab.state.gravity;
  const friction = obj.friction;
  const ropeFriction = obj.ropeFriction;
  const denominator = m1 + m2 + I / (r * r);
  let a = (m2 - m1) * g / denominator;
  if (Math.abs(obj.velocity) > 0.001) {
    const frictionForce = friction * (m1 + m2) * g;
    const frictionAcc = frictionForce / denominator;
    if (a > 0) a = Math.max(0, a - frictionAcc);
    else if (a < 0) a = Math.min(0, a + frictionAcc);
  }
  const angularFriction = Math.abs(obj.angularVelocity) * ropeFriction;
  obj.velocity = (obj.velocity || 0) + a * dt;
  obj.velocity *= (1 - friction * dt * 0.3);
  obj.angularVelocity = (obj.angularVelocity || 0) + (a / r) * dt;
  obj.angularVelocity *= (1 - angularFriction * dt);
  obj.rotationAngle = (obj.rotationAngle || 0) + obj.angularVelocity * dt * 30;
  let leftNewY = (obj.leftPosition || 420) - obj.velocity * dt;
  let rightNewY = (obj.rightPosition || 420) + obj.velocity * dt;
  const minY = obj.y + obj.w + 15;
  const maxY = 620;
  leftNewY = Math.max(minY, Math.min(maxY, leftNewY));
  rightNewY = Math.max(minY, Math.min(maxY, rightNewY));
  obj.leftPosition = leftNewY;
  obj.rightPosition = rightNewY;
  if (obj.leftMassObj) obj.leftMassObj.y = obj.leftPosition;
  if (obj.rightMassObj) obj.rightMassObj.y = obj.rightPosition;
}

objects.draw:
function(ctx, obj) {
  ctx.save();
  ctx.shadowBlur = 6;
  ctx.shadowColor = 'rgba(0,0,0,0.25)';
  ctx.beginPath();
  ctx.arc(obj.x, obj.y, obj.w, 0, Math.PI * 2);
  const grad = ctx.createLinearGradient(obj.x - obj.w * 0.4, obj.y - obj.w * 0.3, obj.x + obj.w * 0.4, obj.y + obj.w * 0.5);
  grad.addColorStop(0, obj.fill);
  grad.addColorStop(1, obj.stroke);
  ctx.fillStyle = grad;
  ctx.fill();
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = obj.lineWidth;
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(obj.x - obj.w * 0.2, obj.y - obj.w * 0.2, obj.w * 0.2, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(255,255,255,0.5)';
  ctx.fill();
  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold ' + Math.max(11, obj.w * 0.55) + 'px monospace';
  ctx.shadowBlur = 2;
  ctx.fillText(obj.mass + ' kg', obj.x - 13, obj.y + 6);
  ctx.beginPath();
  ctx.arc(obj.x, obj.y - obj.w * 0.85, 5, 0, Math.PI * 2);
  ctx.fillStyle = '#8b5cf6';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(obj.x, obj.y - obj.w * 0.85, 2.5, 0, Math.PI * 2);
  ctx.fillStyle = '#facc15';
  ctx.fill();
  ctx.restore();
}

tools.action:
function() {
  const centerX = Lab.state.W / 2;
  const pulleyY = 130;
  const massStartY = 440;

  const existing = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (existing) {
    if (confirm('Já existe uma máquina. Deseja recriar?')) {
      Lab.state.objects.filter(o => o.pluginId === 'atwood_pulley').forEach(o => Lab.objects.remove(o.id));
      Lab.state.objects.filter(o => o.pluginId === 'atwood_mass').forEach(o => Lab.objects.remove(o.id));
    } else { return; }
  }

  const pulley = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_pulley',
    x: centerX,
    y: pulleyY,
    w: 48,
    static: true,
    leftMass: 1,
    rightMass: 1.2,
    leftPosition: massStartY,
    rightPosition: massStartY,
    fill: '#e2e8f0',
    stroke: '#475569',
    lineWidth: 2
  });

  const leftMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX - 95,
    y: massStartY,
    w: 28,
    mass: 1,
    fill: '#3b82f6',
    stroke: '#1d4ed8',
    lineWidth: 2
  });

  const rightMass = Lab.objects.add({
    type: 'circle',
    pluginId: 'atwood_mass',
    x: centerX + 95,
    y: massStartY,
    w: 28,
    mass: 1.2,
    fill: '#ef4444',
    stroke: '#dc2626',
    lineWidth: 2
  });

  const pulleyObj = Lab.objects.get(pulley);
  pulleyObj.leftMassObj = Lab.objects.get(leftMass);
  pulleyObj.rightMassObj = Lab.objects.get(rightMass);

  alert('✅ Máquina de Atwood criada!\n\nMassa esquerda: 1.0 kg\nMassa direita: 1.2 kg\n\nSelecione a roldana para ajustar os parâmetros.');
}

function() {
  const p = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!p) { alert('Crie a máquina primeiro.'); return; }
  const m1 = parseFloat(prompt('Massa esquerda (kg):', p.leftMass));
  const m2 = parseFloat(prompt('Massa direita (kg):', p.rightMass));
  if (!isNaN(m1) && !isNaN(m2) && m1 > 0 && m2 > 0) {
    p.leftMass = m1;
    p.rightMass = m2;
    if (p.leftMassObj) p.leftMassObj.mass = m1;
    if (p.rightMassObj) p.rightMassObj.mass = m2;
    alert('✅ Massas ajustadas!\nEsquerda: ' + m1 + ' kg\nDireita: ' + m2 + ' kg');
  }
}

function() {
  const p = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!p) { alert('Crie a máquina primeiro.'); return; }
  const startY = 440;
  p.leftPosition = startY;
  p.rightPosition = startY;
  p.velocity = 0;
  p.angularVelocity = 0;
  p.rotationAngle = 0;
  if (p.leftMassObj) p.leftMassObj.y = startY;
  if (p.rightMassObj) p.rightMassObj.y = startY;
  Lab.render.all();
  alert('✅ Posições resetadas!');
}

function() {
  const p = Lab.state.objects.find(o => o.pluginId === 'atwood_pulley');
  if (!p) { alert('Crie a máquina primeiro.'); return; }
  const m1 = p.leftMass;
  const m2 = p.rightMass;
  const I = p.momentOfInertia;
  const r = p.w / 100;
  const g = 9.8;
  const denom = m1 + m2 + I / (r * r);
  const a = Math.abs(m2 - m1) * g / denom;
  const T = (2 * m1 * m2 * g) / denom;
  alert('📊 MÁQUINA DE ATWOOD\n\n' +
    'Massa esquerda: ' + m1 + ' kg\n' +
    'Massa direita: ' + m2 + ' kg\n' +
    'Diferença: ' + Math.abs(m1 - m2).toFixed(2) + ' kg\n\n' +
    'Raio da roldana: ' + p.w + ' px\n' +
    'Inércia: ' + I + '\n' +
    'Atrito corda: ' + p.friction + '\n' +
    'Atrito roldana: ' + p.ropeFriction + '\n\n' +
    'Aceleração: ' + a.toFixed(3) + ' m/s²\n' +
    'Tensão: ' + T.toFixed(2) + ' N\n' +
    'Velocidade: ' + (p.velocity || 0).toFixed(2) + ' m/s');
}
